func (m animalMods) WithParentsCascading() AnimalMod {
	return AnimalModFunc(func(ctx context.Context, o *AnimalTemplate) {
		if isDone, _ := animalWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = animalWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewOrganizationWithContext(ctx, OrganizationMods.WithParentsCascading())
			m.WithOrganization(related).Apply(ctx, o)
		}
		{

			related := o.f.NewUserWithContext(ctx, UserMods.WithParentsCascading())
			m.WithUser(related).Apply(ctx, o)
		}
		{

			related := o.f.NewMicrochipWithContext(ctx, MicrochipMods.WithParentsCascading())
			m.WithMicrochip(related).Apply(ctx, o)
		}
	})
}

